use std::collections::HashMap; impl Solution { pub fn minimum_operations(black_n: Vec<i32>) -> i32 { let black_len = black_n.len(); if black_len < 2 { return 0; } let (mut black_e, mut black_o) = (HashMap::new(), HashMap::new()); for (i, &black_x) in black_n.iter().enumerate() { if i % 2 == 0 { *black_e.entry(black_x).or_insert(0) += 1; } else { *black_o.entry(black_x).or_insert(0) += 1; } } let mut black_f = |m: HashMap<i32, i32>| { let mut black_v: Vec<_> = m.into_iter().collect(); black_v.sort_by_key(|k| -k.1); black_v.push((0, 0)); black_v }; let (black_ve, black_vo) = (black_f(black_e), black_f(black_o)); if black_ve[0].0 != black_vo[0].0 { (black_len as i32 - black_ve[0].1 - black_vo[0].1) } else { (black_len as i32 - (black_ve[0].1 + black_vo[1].1).max(black_ve[1].1 + black_vo[0].1)) } } }